import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.Bjylvv1V.js";const p=JSON.parse('{"title":"월말 마감","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/month-closing.md","filePath":"guide/scenarios/month-closing.md","lastUpdated":1771991831000}'),o={name:"guide/scenarios/month-closing.md"};function i(n,a,h,s,c,d){return e(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="월말-마감" tabindex="-1">월말 마감 <a class="header-anchor" href="#월말-마감" aria-label="Permalink to &quot;월말 마감&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 40분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 매월 말</p></blockquote><p>한 달간의 모든 부과·수납·회계 처리를 마감하고, 재무제표를 확정하는 프로세스입니다. 마감 후에는 해당 월의 데이터 수정이 제한됩니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 수납 마감 확인        (5분)  → 미처리 수납 건 정리</span></span>
<span class="line"><span>2. 전표 점검            (10분) → 누락·오류 전표 확인</span></span>
<span class="line"><span>3. 통장 대사            (10분) → 장부 vs 통장 잔액 일치 확인</span></span>
<span class="line"><span>4. 재무제표 작성         (10분) → 시산표·대차대조표·손익계산서</span></span>
<span class="line"><span>5. 월마감 실행          (2분)  → 회계 월마감 처리</span></span>
<span class="line"><span>6. 결재 요청            (3분)  → 대표회의 결재</span></span></code></pre></div><hr><h2 id="_1단계-수납-마감-확인-5분" tabindex="-1">1단계: 수납 마감 확인 (5분) <a class="header-anchor" href="#_1단계-수납-마감-확인-5분" aria-label="Permalink to &quot;1단계: 수납 마감 확인 (5분)&quot;">​</a></h2><p>월말 마감 전에 해당 월의 수납이 모두 처리되었는지 확인합니다.</p><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 자동이체 결과가 모두 반영되었는가? → <a href="/recp/auto-transfer.html">자동이체수납</a></li><li>[ ] 수납 오류 건이 모두 처리되었는가? → <a href="/recp/process.html">수납처리</a> &gt; 자동수납오류처리</li><li>[ ] 가수금(미확인 입금)이 정리되었는가? → <a href="/recp/process.html">수납처리</a> &gt; 가수금관리</li><li>[ ] 수납 전표 연계가 완료되었는가? → <a href="/recp/process.html">수납처리</a> &gt; 수납전표연계</li></ul><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/inquiry.html">수납조회</a> &gt; 수납집계표 (RECP5060)</p></blockquote><p>수납집계표에서 해당 월의 총 수납액을 확인합니다.</p><hr><h2 id="_2단계-전표-점검-10분" tabindex="-1">2단계: 전표 점검 (10분) <a class="header-anchor" href="#_2단계-전표-점검-10분" aria-label="Permalink to &quot;2단계: 전표 점검 (10분)&quot;">​</a></h2><p>해당 월에 입력된 모든 회계 전표를 점검합니다.</p><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표조회 (ACCT2022)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>전표조회 화면 진입</li><li>조회 기간: 해당 월 1일 ~ 말일</li><li><strong>조회</strong> 실행</li><li>전표 목록을 확인하며 아래 항목 점검</li></ol><h3 id="점검-항목" tabindex="-1">점검 항목 <a class="header-anchor" href="#점검-항목" aria-label="Permalink to &quot;점검 항목&quot;">​</a></h3><ul><li>[ ] 모든 지출 전표가 입력되었는가? (통장 거래내역과 비교)</li><li>[ ] 차변 합계 = 대변 합계인가? (불일치 시 저장 자체가 안 됨)</li><li>[ ] 적요(거래 설명)가 정확한가?</li><li>[ ] 잘못된 계정과목으로 입력된 건이 없는가?</li><li>[ ] 수납 전표(자동 생성)가 정상인가?</li></ul><h3 id="일계표-확인" tabindex="-1">일계표 확인 <a class="header-anchor" href="#일계표-확인" aria-label="Permalink to &quot;일계표 확인&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 일계표 (ACCT2070)</p></blockquote><p>일별 차변/대변 합계가 일치하는지 확인합니다.</p><h3 id="월계표-확인" tabindex="-1">월계표 확인 <a class="header-anchor" href="#월계표-확인" aria-label="Permalink to &quot;월계표 확인&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 월계표 (ACCT2080)</p></blockquote><p>월간 계정과목별 차변/대변 합계를 확인합니다.</p><hr><h2 id="_3단계-통장-대사-10분" tabindex="-1">3단계: 통장 대사 (10분) <a class="header-anchor" href="#_3단계-통장-대사-10분" aria-label="Permalink to &quot;3단계: 통장 대사 (10분)&quot;">​</a></h2><p>시스템의 계좌 잔액과 실제 통장 잔액이 일치하는지 확인합니다.</p><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transaction.html">은행거래내역</a> (BANK0010)</p></blockquote><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>은행거래내역 화면에서 해당 월 거래내역 조회</li><li>시스템에 기록된 잔액 확인</li><li>실제 통장 잔액(인터넷뱅킹 또는 잔액증명서)과 비교</li></ol><h3 id="추가-확인" tabindex="-1">추가 확인 <a class="header-anchor" href="#추가-확인" aria-label="Permalink to &quot;추가 확인&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 제예금명세서 (ACCT2100)</p></blockquote><p>계좌별 잔액 명세를 확인하여 통장과 대사합니다.</p><h3 id="불일치-시-원인-파악" tabindex="-1">불일치 시 원인 파악 <a class="header-anchor" href="#불일치-시-원인-파악" aria-label="Permalink to &quot;불일치 시 원인 파악&quot;">​</a></h3><table tabindex="0"><thead><tr><th>차이 원인</th><th>확인 방법</th></tr></thead><tbody><tr><td>미입력 지출 전표</td><td>통장 출금 내역 중 전표 미입력 건 찾기</td></tr><tr><td>미입력 수납</td><td>통장 입금 내역 중 수납 미처리 건 찾기</td></tr><tr><td>이체 시차</td><td>월말 이체 건이 다음 달에 반영된 경우</td></tr><tr><td>카드 결제 미반영</td><td>카드 승인일 vs 결제일 차이</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">반드시 일치시키세요</p><p>통장 잔액과 시스템 잔액이 일치하지 않으면 재무제표의 신뢰성이 떨어집니다. 차이 원인을 반드시 파악하고 조정하세요.</p></div><hr><h2 id="_4단계-재무제표-작성-10분" tabindex="-1">4단계: 재무제표 작성 (10분) <a class="header-anchor" href="#_4단계-재무제표-작성-10분" aria-label="Permalink to &quot;4단계: 재무제표 작성 (10분)&quot;">​</a></h2><h3 id="합계잔액시산표" tabindex="-1">합계잔액시산표 <a class="header-anchor" href="#합계잔액시산표" aria-label="Permalink to &quot;합계잔액시산표&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 합계잔액시산표 (ACCT4010)</p></blockquote><ol><li>기간 설정 (해당 월)</li><li><strong>조회</strong> 실행</li><li><strong>차변 합계 = 대변 합계</strong> 확인 → 일치하지 않으면 전표 오류</li></ol><h3 id="대차대조표" tabindex="-1">대차대조표 <a class="header-anchor" href="#대차대조표" aria-label="Permalink to &quot;대차대조표&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 대차대조표 (ACCT4020)</p></blockquote><p>해당 시점의 자산·부채·자본 현황을 확인합니다.</p><h3 id="손익계산서" tabindex="-1">손익계산서 <a class="header-anchor" href="#손익계산서" aria-label="Permalink to &quot;손익계산서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 손익계산서 (ACCT4030)</p></blockquote><p>해당 기간의 수입·지출·손익을 확인합니다.</p><h3 id="세입세출서" tabindex="-1">세입세출서 <a class="header-anchor" href="#세입세출서" aria-label="Permalink to &quot;세입세출서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 세입세출서 (ACCT4080)</p></blockquote><p>예산 대비 실적을 확인합니다. 계산식: (실적 ÷ 예산) × 100</p><h3 id="체크리스트-1" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트-1" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 시산표의 차변 합계 = 대변 합계인가?</li><li>[ ] 대차대조표의 자산 = 부채 + 자본인가?</li><li>[ ] 손익계산서의 수입·지출이 합리적인가?</li><li>[ ] 예산 대비 과다 지출 항목이 없는가?</li></ul><hr><h2 id="_5단계-월마감-실행-2분" tabindex="-1">5단계: 월마감 실행 (2분) <a class="header-anchor" href="#_5단계-월마감-실행-2분" aria-label="Permalink to &quot;5단계: 월마감 실행 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/basic.html">기초정보</a> &gt; 월마감 (ACCT1092)</p></blockquote><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>월마감 화면 진입</li><li>마감할 연월 선택</li><li><strong>마감</strong> 실행</li></ol><div class="danger custom-block"><p class="custom-block-title">마감 후 수정 제한</p><p>월마감 후에는 해당 월의 전표 입력·수정·삭제가 제한됩니다. 마감 해제는 관리자 권한이 필요합니다. 모든 점검을 완료한 후 마감하세요.</p></div><hr><h2 id="_6단계-결재-요청-3분" tabindex="-1">6단계: 결재 요청 (3분) <a class="header-anchor" href="#_6단계-결재-요청-3분" aria-label="Permalink to &quot;6단계: 결재 요청 (3분)&quot;">​</a></h2><p>재무제표를 확정한 후 대표회의 결재를 받습니다.</p><blockquote><p><strong>메뉴 경로</strong>: <a href="/appr/">Xp전자결재</a></p></blockquote><ol><li>결재 문서 작성 (재무제표 첨부)</li><li>결재선 지정</li><li>결재 요청 전송</li></ol><hr><h2 id="월말-마감-최종-체크리스트" tabindex="-1">월말 마감 최종 체크리스트 <a class="header-anchor" href="#월말-마감-최종-체크리스트" aria-label="Permalink to &quot;월말 마감 최종 체크리스트&quot;">​</a></h2><h3 id="마감-전-필수-확인" tabindex="-1">마감 전 필수 확인 <a class="header-anchor" href="#마감-전-필수-확인" aria-label="Permalink to &quot;마감 전 필수 확인&quot;">​</a></h3><ul><li>[ ] 모든 수납이 처리되었는가?</li><li>[ ] 모든 전표가 입력되었는가?</li><li>[ ] 통장 잔액과 시스템 잔액이 일치하는가?</li><li>[ ] 미수금/회계 비교가 일치하는가?</li><li>[ ] 시산표 차변 = 대변인가?</li><li>[ ] 재무제표에 이상이 없는가?</li></ul><h3 id="마감-후-작업" tabindex="-1">마감 후 작업 <a class="header-anchor" href="#마감-후-작업" aria-label="Permalink to &quot;마감 후 작업&quot;">​</a></h3><ul><li>[ ] 재무제표 결재 요청</li><li>[ ] 미납 세대 독촉장 발송 (<a href="/guide/scenarios/overdue.html">미수금 관리</a>)</li><li>[ ] 다음 달 부과 준비 사항 확인</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="시산표-차변-대변이-안-맞아요" tabindex="-1">시산표 차변/대변이 안 맞아요 <a class="header-anchor" href="#시산표-차변-대변이-안-맞아요" aria-label="Permalink to &quot;시산표 차변/대변이 안 맞아요&quot;">​</a></h3><p><strong>원인</strong>: 전표 입력 시 차변/대변이 불균형한 건이 존재 <strong>해결</strong>: 전표조회(ACCT2022)에서 해당 월의 전표를 모두 확인하세요. 정상이라면 차변과 대변이 일치하지 않는 전표는 저장이 안 되므로, 수정이력(ACCT2054)을 확인하세요.</p><h3 id="통장-잔액이-안-맞아요" tabindex="-1">통장 잔액이 안 맞아요 <a class="header-anchor" href="#통장-잔액이-안-맞아요" aria-label="Permalink to &quot;통장 잔액이 안 맞아요&quot;">​</a></h3><p><strong>원인</strong>: 미입력 전표, 이체 시차, 수납 미처리 등 <strong>해결</strong>: <a href="/guide/scenarios/bank-reconciliation.html">통장 대사</a> 시나리오를 참고하여 체계적으로 차이 원인을 파악하세요.</p><h3 id="마감을-해제하고-싶어요" tabindex="-1">마감을 해제하고 싶어요 <a class="header-anchor" href="#마감을-해제하고-싶어요" aria-label="Permalink to &quot;마감을 해제하고 싶어요&quot;">​</a></h3><p><strong>원인</strong>: 마감 후 오류를 발견한 경우 <strong>해결</strong>: 관리자 권한이 있는 담당자에게 마감 해제를 요청하세요. 해제 후 수정하고 다시 마감합니다.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/acct/voucher.html">전표관리</a> - 전표 입력·조회</li><li><a href="/acct/ledger.html">장부관리</a> - 원장·보조부</li><li><a href="/acct/settlement.html">결산관리</a> - 재무제표</li><li><a href="/bank/transaction.html">은행거래내역</a> - 통장 대사</li><li><a href="/recp/inquiry.html">수납조회</a> - 수납 확인</li><li><a href="/recp/overdue.html">미납조회</a> - 미납 현황</li></ul>`,82)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
